          ]
        },
        {
          "questionText": "What is the term for the conductors that connect incoming metallic services, like water or gas pipes, to the earthing system?",
          "answerGuidance": [
            "Main protective bonding",
            "Main bonding",
            "Protective bonding conductors"
          ]
        }
      ],
      "deeperQuestionText": "How does a protective device, such as a fuse, fulfill its role within the ADS strategy during a fault?",
      "deeperAnswerGuidance": [
        "It provides the automatic disconnection of the supply",
        "It reacts to the high current flowing through the earth path",
        "It breaks the circuit to prevent a sustained electric shock",
        "It works in conjunction with the CPC and earthing conductor"
      ],
      "hint": "Distinguish between the conductors used for circuits, the conductors used for pipes, and the device that actually cuts the power."
    }
  ]
}

{
  "integrative": {
    "title": "Integrative Close",
    "objective": "Synthesize the relationship between a specific earthing system and the unique ADS components required to achieve Automatic Disconnection of Supply.",
    "retrievalTextLines": [
      "Earthing systems are defined by how they connect to the source of earth.",
      "ADS relies on a complete path from the installation back to the transformer.",
      "In systems without a supplier earth, the installer must provide the connection point and the link to the main terminal."
    ],
    "questionText": "You are wiring a remote stable block where the supplier provides Phase and Neutral but no earth terminal. Identify the required earthing system type, the specific ADS component you must install in the ground to provide an earth path, and the name of the conductor that connects this ground-source to the installation's main earthing terminal.",
    "answerGuidance": [
      "TT system",
      "Earth electrode",
      "Earthing conductor"
    ],
    "hint": "Recall the Latin term for 'Earth-Earth'. You need a physical rod and the main cable that bridges the gap between that rod and the building's consumer unit area."
  }
}

